mapper.select:
select id, policy_id, content, cast(metadata as text) as metadata_json, created_at, updated_at from lego_memory_items where policy_id = #{policyId}
and coalesce(metadata->>'memoryNamespace','') = #{memoryNamespace}
and (metadata->>'strategyKind' is null or metadata->>'strategyKind' = #{strategyKind})
and content ilike '%' || #{q} || '%'
order by
word_similarity(#{q}, content) desc nulls last, coalesce(updated_at, created_at) desc nulls last, created_at desc
coalesce(updated_at, created_at) desc, created_at desc
limit #{limit}

select id
from lego_memory_items
where policy_id = #{policyId}
and content = #{content}


        and coalesce(metadata->>'memoryNamespace','') = #{memoryNamespace}


        and (metadata->>'memoryNamespace' is null or btrim(metadata->>'memoryNamespace') = '')



    and (metadata->>'strategyKind' is null or metadata->>'strategyKind' = #{strategyKind})

limit 1

mapper.update:
update lego_memory_items
set updated_at = now()
where id = #{id}

mapper.delete:
delete
from lego_memory_items
where id = #{itemId}
  and policy_id = #{policyId}
